import type { PropsWithChildren } from 'react';
import React from 'react';

import type { MenuItemProps } from './MenuItem/MenuItem.types';

export const getMaxDepth = (children: React.ReactNode, currentDepth = 0): number => {
	if (!children) {
		return currentDepth;
	}

	let maxDepth = currentDepth;
	React.Children.forEach(children, child => {
		if (React.isValidElement<PropsWithChildren>(child)) {
			const childDepth = getMaxDepth(child.props.children, currentDepth + 1);
			if (childDepth > maxDepth) {
				maxDepth = childDepth;
			}
		}
	});

	return maxDepth;
};

export const isMenuItem = (child: React.ReactElement): boolean =>
	child.type && (child.type as any).displayName === 'MenuItem';

export const processChildrenWithProps = <P extends object>(
	children: React.ReactNode,
	additionalProps: P,
	id: string,
): React.ReactNode => {
	let itemCount = 0;

	return React.Children.map(children, child => {
		const itemId = `${id}${id === '' ? '' : '-'}${itemCount}`;

		if (!React.isValidElement<MenuItemProps>(child) || !(isMenuItem(child) && !child.props.disabled)) {
			return child;
		}

		itemCount++;
		return React.cloneElement(child, { ...additionalProps, id: itemId } as P & React.Attributes);
	});
};
